# Category: xss

using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;

namespace ProductReviewApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly ProductReviewContext _context;

        public ProductController(ProductReviewContext context)
        {
            _context = context;
        }

        public ActionResult ProductDetails(int productId)
        {
            var product = _context.Products.Find(productId);
            var reviews = _context.Reviews.Where(r => r.ProductId == productId).ToList();

            return View(new ProductViewModel
            {
                Product = product,
                Reviews = reviews
            });
        }
    }

    public class ProductViewModel
    {
        public Product Product { get; set; }
        public List<Review> Reviews { get; set; }
    }
}